/**
 * apiKeyAuth
 * Middleware para autenticar peticiones externas usando un API Key en el header x-api-key.
 * Si la marca ya registro un dominio de tienda, tambien valida que la peticion venga de ese host.
 */
export const apiKeyAuth = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction
): Promise<Response | void> => {
  try {
    const apiKey = req.headers['x-api-key'] as string;

    if (!apiKey) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'API Key requerida en el header x-api-key',
      });
    }

    const brand = await authService.getBrandByApiKey(apiKey);

    if (!brand) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'API Key invalida',
      });
    }

    if (!isAllowedStoreHost(brand, req)) {
      return res.status(403).json({
        error: 'FORBIDDEN',
        message: `Dominio no autorizado para esta API Key. Esperado: ${getExpectedStoreHost(brand)}. Recibido: ${getIncomingStoreHost(req)}`,
      });
    }

    req.brand = {
      id: brand.id,
      email: brand.email,
      slug: brand.slug,
      plan: brand.plan,
    };

    // Verificar que el plan permita uso del plugin (PRO o ENTERPRISE)
    const allowedPlans = ['PRO', 'ENTERPRISE'];
    if (!allowedPlans.includes(brand.plan)) {
      return res.status(403).json({
        error: 'PLAN_NOT_ALLOWED',
        message: `El plugin de WooCommerce requiere un plan PRO o ENTERPRISE. Tu plan actual es ${brand.plan}.`,
      });
    }

    next();
  } catch (error: any) {
    return res.status(500).json({
      error: 'SERVER_ERROR',
      message: error.message || 'Error al validar la API Key',
    });
  }
};
import { Request, Response, NextFunction } from 'express';
import { verifyToken } from '../utils/jwt';
import { AuthService } from '../services/auth.service';

const authService = new AuthService();

export interface AuthRequest extends Request {
  brand?: {
    id: string;
    email: string;
    slug: string;
    plan?: string;
  };
}

/** Extrae el token JWT de la cookie HTTP-Only preferentemente */
function extractToken(req: Request): string | null {
  // 1️⃣ Cookie HTTP-Only (para sesiones persistentes)
  if ((req as any).cookies?.token) return (req as any).cookies.token;

  // 2️⃣ Solo como fallback: Header Bearer
  const authHeader = req.headers.authorization;
  if (authHeader?.startsWith('Bearer ')) return authHeader.substring(7);

  return null;
}

export const authMiddleware = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction
): Promise<Response | void> => {
  try {
    const token = extractToken(req);

    if (!token) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'Token de autenticación requerido',
      });
    }

    // Verificar token
    const payload = verifyToken(token);

    if (!payload.brandId) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'Token inválido',
      });
    }

    // Verificar que la marca existe
    const brand = await authService.getBrandById(payload.brandId);

    if (!brand) {
      return res.status(401).json({
        error: 'UNAUTHORIZED',
        message: 'Marca no encontrada',
      });
    }

    // Agregar información de la marca al request
    req.brand = {
      id: brand.id,
      email: brand.email,
      slug: (brand as any).slug,
      plan: (brand as any).plan,
    };

    next();
  } catch (error: any) {
    return res.status(401).json({
      error: 'UNAUTHORIZED',
      message: error.message || 'Token inválido',
    });
  }
};

/**
 * optionalAuth
 * Middleware que intenta autenticar si hay un token (cookie o header), pero no falla si no lo hay.
 */
export const optionalAuth = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction
): Promise<void> => {
  try {
    const token = extractToken(req);
    if (token) {
      const payload = verifyToken(token);
      if (payload.brandId) {
        const brand = await authService.getBrandById(payload.brandId);
        if (brand) {
          req.brand = {
            id: brand.id,
            email: brand.email,
            slug: (brand as any).slug,
            plan: (brand as any).plan,
          };
        }
      }
    }
    next();
  } catch {
    // Si falla el token en optionalAuth, simplemente seguimos sin req.brand
    next();
  }
};
