export class LimitExceededError extends AppError {
  public usage?: {
    used: number;
    limit: number;
  };

  constructor(message: string, usage?: { used: number; limit: number }) {
    super(message, 403, 'LIMIT_EXCEEDED');
    this.usage = usage;
  }
