    const logData = {
      timestamp,
      message: error.message,
      stack: error.stack,
      method: req?.method,
      path: req?.path,
      body: req?.body,
      query: req?.query,
      params: req?.params,
      ip: req?.ip,
    };

    if (error instanceof AppError && error.isOperational) {
      // Error operacional esperado
      console.warn('⚠️  Error Operacional:', JSON.stringify(logData, null, 2));
    } else {
      // Error inesperado del sistema
      console.error('❌ Error del Sistema:', JSON.stringify(logData, null, 2));
