    res.status(429).json({
      error: 'GLOBAL_RATE_LIMIT_EXCEEDED',
      message: 'Demasiadas solicitudes. Por favor intenta de nuevo más tarde.',
      retryAfter: '15 minutos',
      timestamp: new Date().toISOString(),
    });
  },
  skip: (req: Request) => {
    // Omitir health check del rate limiting global
    if (req.path === '/health') {
      return true;
    }
    if (process.env.NODE_ENV === 'development' && req.ip === '::1') {
      return true;
    }
    return false;
  },
});
import { Request, Response, NextFunction } from 'express';

// Log para rutas importantes (pagos, tryon, integraciones)
export const requestLogger = (req: Request, res: Response, next: NextFunction) => {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    if (res.statusCode >= 400 || duration > 1000 || req.path.includes('/payment') || req.path.includes('/generate')) {
      console.log(`[${new Date().toISOString()}] ${req.method} ${req.originalUrl} (${res.statusCode}) - ${duration}ms`);
    }
  });

  next();
};

